var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"체엣…… 그 입만 산 자식, 생긴 대로 음흉한 짓만 골라 하네.","JPN":"ちぇ……あの口先ばかりのやつ、見た目どおり腹黒いことしやがるね。","ENG":"Tch... That guy's all talk. I guess he's as treacherous as he looks.","TWN":"嘖……那個牙尖嘴利的傢伙，行為跟他的長相一樣陰險。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"유령의 집에는 유령이 사는 거지? 착한 유령이면 좋겠다.","JPN":"お化け屋敷にはお化けが住んでるんでしょ？　いいお化けだったらいいなあ。","ENG":"Ghosts live inside haunted mansions, right? I hope they are friendly ghosts.","TWN":"鬼屋是鬼住的地方吧？希望是善良的鬼。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시그마, 혹시 내가 도전을 포기하자고 하면 어떡할 거야?","JPN":"シグマ、もし僕が挑戦を諦めようと言ったらどうする？","ENG":"Sigma? What will you do if I tell you to give up this challenge?","TWN":"西格瑪，我說要放棄的話，你會怎麼辦？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"왜? 루트는 하기 싫어?","JPN":"なんで？　ルートはやりたくないの？","ENG":"Why would I? You don't want to do it, Root?","TWN":"為什麼要放棄，你不想玩嗎？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"롤러코스터도 이상했잖아. 그런 위험한 건 더 이상 놀이기구가 아니야.","JPN":"ジェットコースターも変だった。あんなに危ないのはもうアトラクションとはいえない。","ENG":"The roller coaster was weird. It's not supposed to be that dangerous.","TWN":"剛剛的雲霄飛車就很奇怪，那麼危險的東西根本不能算是遊樂器材。"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"저 유령의 집도…… 나쁜 느낌이 들어.","JPN":"お化け屋敷も……嫌な予感がするんだ。","ENG":"And that haunted mansion... I have a bad feeling about it.","TWN":"而這次的鬼屋……我也有不好的預感。"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그치만 나는 지금 정말 즐거운걸.","JPN":"でも、私は今すっごく楽しいよ。","ENG":"But I'm having a blast.","TWN":"可是我玩得正開心欸？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"뭐어? 롤러코스터는 싫다고 했으면서?","JPN":"ええ？　ジェットコースターはイヤだって言ったじゃないか。","ENG":"Huh? I thought you said you didn't like the roller coaster?","TWN":"什麼？你不是說討厭雲霄飛車嗎？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"내가 재미있는 건 친구들을 도와주는 일이거든.","JPN":"私が楽しいと思うのは、友達を助けてあげることだもん。","ENG":"You see, what I enjoy is helping my friends.","TWN":"我覺得好玩的部分是幫助朋友。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"친구들을……?","JPN":"友達を……？","ENG":"Your friends...?","TWN":"幫助朋友……？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"행복해지길 바라는 것만으로도 살아갈 수 있어.","JPN":"幸せになるように願うだけでも生きていけるんだよ。","ENG":"I'm perfectly fine living my life wishing for others to be happy.","TWN":"想變幸福，是我活下去的動力。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"하지만 세상에는 그런 바람을 가질 수 없는 사람들이 많이 있었던 거야.","JPN":"でもこの世界にはそんな願いすら持てない人がいっぱいいたの。","ENG":"But there are a lot of people in this world who could never wish for something like that.","TWN":"但世界上有很多人無法有這樣的希望。"},"stage":{"bg":"CAMP_01","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"나무 인형이 원래대로 돌아가기로 한 건 나무꾼이 선물해 준 행복한 시간 덕분이야.","JPN":"木彫り人形が元どおりに戻ろうと決めたのは、木こりがくれた幸せな時間のおかげだったんだ。","ENG":"The reason the girl decided to turn back into a wooden doll was because the woodcutter gave her the best gift she could ever receive: happiness.","TWN":"木偶之所以決定回到原本的樣子，是因為樵夫送給他的幸福時光。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"행복을 모르고 지금에 익숙해져 버리면, 행복을 바라는 법도 알 수가 없거든.","JPN":"幸せを知らないまま現実に慣れちゃうと、幸せを願う方法もわからなくなるから。","ENG":"If you don't know what happiness is, and get used to being without it, you won't even know how to wish for it.","TWN":"沒嚐過幸福的滋味，就這樣安於現況的話，就不知道要如何期待幸福。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"시그마는……. 사람들이 행복을 찾을 수 있게 도와주는 게 즐겁단 뜻이지?","JPN":"シグマは……人が幸せを見つけられるように手伝うことが楽しいってことだよね？","ENG":"So, you mean... you enjoy helping others find happiness, right?","TWN":"西格瑪……你的意思是，幫助人找到幸福是你快樂的來源嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};